      "expected_outputs": {
        "answer": "name of the most-insulted ingredient",
        "supporting_points": "quoted insulting transcript spans grouped by ingredient",
        "analysis": "reasoning about which ingredient wins"
      }
    },
    {
      "step_id": 2,
      "tool_name": "frame_retriever",
      "purpose": "Retrieve a chronological set of candidate frames across the full burger-making portion where the target ingredient may appear, preserving enough coverage to count distinct appearances with or without a cutting board background.",
      "inputs": {
        "clips": [
          {
            "video_id": "nq9WnmCGoFQ",
            "start_s": 0.0,
            "end_s": 300.0
          }
        ],
        "time_hints": [
          "0-3s finished burger on board may include lettuce",
          "60-64s whole lettuce on floor",
          "86-109s slicing and mention of crispy water",
          "109-130s mise en place with shredded crispy water",
          "120-125s ingredients laid out on cutting board",
          "237-259s burger assembly with shredded crispy water"
        ],
        "query": "chronological frames showing the ingredient identified as most insulted, especially lettuce or shredded crispy water, including all distinct appearances and whether a cutting board is visible in the background",
        "num_frames": 14,
        "sequence_mode": "chronological",
        "neighbor_radius_s": 0.0,
        "include_anchor_neighbors": false,
        "sort_order": "chronological"
      },
      "input_refs": {},
      "expected_outputs": {
        "frames": "chronological candidate frames spanning all likely appearances of the target ingredient"
      }
    },
    {
      "step_id": 3,
      "tool_name": "generic_purpose",
      "purpose": "From the retrieved frames plus the transcript-derived target ingredient, verify which frames actually show that ingredient and count distinct times it is shown with a cutting board in the background.",
      "inputs": {
        "query": "Using the transcript result for the target ingredient and these chronological frames, identify each distinct time the target ingredient is visibly shown. For each distinct appearance, state whether a cutting board is in the background. Deduplicate neighboring frames from the same appearance, count only appearances where the target ingredient is shown and a cutting board is in the background, and map the final count to the multiple-choice options.",
        "clips": [],
        "frames": [],
        "transcripts": [],
        "text_contexts": [],
        "evidence_ids": []
      },
      "input_refs": {
        "frames": [
          {
            "step_id": 2,
            "field_path": "frames"
          }
        ],
        "text_contexts": [
          {
            "step_id": 1,
            "field_path": "answer"
          },
          {
            "step_id": 1,
            "field_path": "supporting_points"
          },
          {
            "step_id": 1,
            "field_path": "analysis"
          }
        ]
      },
      "expected_outputs": {
        "answer": "final option and count",
        "supporting_points": "distinct counted appearances with timestamps/background judgments",
        "analysis": "deduped counting rationale"
      }
    }
  ],
  "refinement_instructions": "Treat step 1 only as identification of the target ingredient from transcript evidence; do not use transcript alone to count visual appearances. In step 3, count distinct appearances rather than raw frames, and reject frames where the ingredient is absent, ambiguous, or only implied by narration. The cutting board condition must be visually verified in the same appearance. If the retrieved frame set misses an early or late candidate appearance, keep the answer unresolved rather than guessing."
